"use strict";(self.webpackChunkdocumentation=self.webpackChunkdocumentation||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Overview","href":"/docs/intro","docId":"intro","unlisted":false},{"type":"link","label":"Managing your inventory","href":"/docs/inventory","docId":"inventory","unlisted":false},{"type":"link","label":"Selling on channels","href":"/docs/channels","docId":"channels","unlisted":false},{"type":"link","label":"Collections and staff picks","href":"/docs/collections","docId":"collections","unlisted":false},{"type":"link","label":"Integrations","href":"/docs/integrations","docId":"integrations","unlisted":false},{"type":"link","label":"ISBN Magic","href":"/docs/isbn-magic","docId":"isbn-magic","unlisted":false},{"type":"link","label":"SFTP Integration Guide for Inventory Uploads","href":"/docs/ftp-integration","docId":"ftp-integration","unlisted":false}]},"docs":{"channels":{"id":"channels","title":"Selling on channels","description":"channels is a Bookhead Connect feature that allows you to sell your books on multiple sales channels. Currently, we support selling books on Squarespace, eBay, and Biblio, and soon we\'ll support Shopify. This automatic inventory data syncing system keeps your bookstore\'s local store inventory up to date on all of your online sales channels.","sidebar":"tutorialSidebar"},"collections":{"id":"collections","title":"Collections and staff picks","description":"Bookhead lets you create curated collections of books to feature on your website and sales channels. Collections are perfect for highlighting staff recommendations, seasonal themes, or any grouping you want to showcase.","sidebar":"tutorialSidebar"},"ftp-integration":{"id":"ftp-integration","title":"SFTP Integration Guide for Inventory Uploads","description":"Bookhead accepts inventory files via secure SFTP (SSH File Transfer Protocol) upload. Upload your CSV file, and we\'ll automatically process it and update your inventory within 15 minutes.","sidebar":"tutorialSidebar"},"integrations":{"id":"integrations","title":"Integrations","description":"Bookhead connects your bookstore system to multiple sales channels. Here\'s what we integrate with and how each one works.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Overview","description":"Bookhead helps your independent bookstore sell books online. We automatically sync your inventory to multiple sales channels - your bookstore system stays the source of truth, and Bookhead keeps everything else in sync.","sidebar":"tutorialSidebar"},"inventory":{"id":"inventory","title":"Managing your inventory","description":"Bookhead provides a platform for connecting your local store inventory with various sales channels. We store your inventory securely in our database, and this gives us the ability to list this inventory on whatever sales channel you want to sell your products on. Because we keep an up-to-date copy of your local inventory, we also have an interface for you to explore and manage the inventory.","sidebar":"tutorialSidebar"},"isbn-magic":{"id":"isbn-magic","title":"ISBN Magic","description":"ISBN Magic is a Google Sheets add-on that looks up bibliographic data for a list of ISBNs \u2014 title, authors, publisher, cover image, dimensions, and more \u2014 and writes the results directly into your spreadsheet.","sidebar":"tutorialSidebar"}}}}')}}]);